SET check_function_bodies = false; CREATE FUNCTION public._get_requests_to_process_ids_helper(in_page integer, in_rows_per_page integer, in_filter_field text, in_filter_data text, in_sort_field text, in_sort_order integer, in_status_exclude text)  RETURNS TABLE(total_count bigint, request_ids bigint[])  LANGUAGE plpgsql  STABLE AS $function$ DECLARE   v_offset integer := GREATEST((in_page - 1), 0) * GREATEST(in_rows_per_page, 1);   v_sort text := 'ASC';   v_order_expr text := 'r.request_id';   v_filter_expr text := 'TRUE';   v_sql text;   v_filter_like text := '%' || COALESCE(in_filter_data, '') || '%';   v_valid_po_statuses text[] := ARRAY['Ordered', 'Inbound', 'Partially Delivered', 'Delivered']; BEGIN   IF in_sort_order = -1 THEN     v_sort := 'DESC';   END IF;    IF in_sort_field = 'request_id' THEN     v_order_expr := 'r.request_id';   ELSIF in_sort_field = 'product_id' THEN     v_order_expr := 'r.product_id';   ELSIF in_sort_field = 'purchase_order_id' THEN     v_order_expr := 'r.purchase_order_id';   ELSIF in_sort_field = 'status' THEN     v_order_expr := 'r.status';   ELSIF in_sort_field = 'priority' THEN     v_order_expr := 'r.priority';   ELSIF in_sort_field = 'ship_to_amz' THEN     v_order_expr := 'r.ship_to_amz';   ELSIF in_sort_field = 'warehouse_qty' THEN     v_order_expr := 'r.warehouse_qty';   ELSIF in_sort_field = 'container_qty' THEN     v_order_expr := 'r.container_qty';   ELSIF in_sort_field = 'deadline' THEN     v_order_expr := 'r.deadline';   ELSIF in_sort_field = 'product_name' THEN     v_order_expr := 'p.name';   ELSIF in_sort_field = 'purchase_order_name' THEN     v_order_expr := 'po.purchase_order_name';   END IF;    IF in_filter_data IS NOT NULL AND btrim(in_filter_data) <> '' THEN     IF in_filter_field = 'status' THEN       v_filter_expr := 'COALESCE(r.status, '''') ILIKE $1';     ELSIF in_filter_field = 'priority' THEN       v_filter_expr := 'COALESCE(r.priority, '''') ILIKE $1';     ELSIF in_filter_field = 'notes' THEN       v_filter_expr := 'COALESCE(r.notes, '''') ILIKE $1';     ELSIF in_filter_field = 'product_name' THEN       v_filter_expr := 'COALESCE(p.name, '''') ILIKE $1';     ELSIF in_filter_field = 'fnsku' THEN       v_filter_expr := 'COALESCE(p.fnsku, '''') ILIKE $1';     ELSIF in_filter_field = 'asin' THEN       v_filter_expr := 'COALESCE(p.asin, '''') ILIKE $1';     ELSIF in_filter_field = 'item_num' THEN       v_filter_expr := 'COALESCE(p.item_num, '''') ILIKE $1';     ELSIF in_filter_field = 'upc' THEN       v_filter_expr := 'COALESCE(p.upc, '''') ILIKE $1';     ELSIF in_filter_field = 'purchase_order_name' THEN       v_filter_expr := 'COALESCE(po.purchase_order_name, '''') ILIKE $1';     ELSE       v_filter_expr := '(         COALESCE(r.notes, '''') ILIKE $1 OR         COALESCE(r.status, '''') ILIKE $1 OR         COALESCE(r.priority, '''') ILIKE $1 OR         COALESCE(p.name, '''') ILIKE $1 OR         COALESCE(p.fnsku, '''') ILIKE $1 OR         COALESCE(p.asin, '''') ILIKE $1 OR         COALESCE(p.item_num, '''') ILIKE $1 OR         COALESCE(p.upc, '''') ILIKE $1 OR         COALESCE(po.purchase_order_name, '''') ILIKE $1       )';     END IF;   END IF;    v_sql := format($fmt$     WITH candidate AS (       SELECT r.request_id       FROM public.requests_to_process r       LEFT JOIN public.products p ON p.product_id = r.product_id       LEFT JOIN public.purchase_orders po ON po.purchase_order_id = r.purchase_order_id       WHERE ($2 IS NULL OR btrim($2) = '' OR r.status IS DISTINCT FROM $2)         AND (           r.purchase_order_id IS NULL           OR po.status = ANY($3)         )         AND %s     ),     paged AS (       SELECT r.request_id       FROM public.requests_to_process r       LEFT JOIN public.products p ON p.product_id = r.product_id       LEFT JOIN public.purchase_orders po ON po.purchase_order_id = r.purchase_order_id       WHERE r.request_id IN (SELECT c.request_id FROM candidate c)       ORDER BY %s %s, r.request_id ASC       OFFSET $4 LIMIT $5     )     SELECT       (SELECT count(*) FROM candidate) AS total_count,       (SELECT array_agg(request_id) FROM paged) AS request_ids   $fmt$, v_filter_expr, v_order_expr, v_sort);    RETURN QUERY EXECUTE v_sql     USING v_filter_like, in_status_exclude, v_valid_po_statuses, v_offset, in_rows_per_page; END; $function$; CREATE FUNCTION public.acquire_record_lock(p_table_name text, p_record_id text, p_editor_name text, p_ttl_seconds integer DEFAULT 120)  RETURNS jsonb  LANGUAGE plpgsql AS $function$ declare     v_lock public.record_locks;     v_existing public.record_locks;     v_ttl integer := greatest(coalesce(p_ttl_seconds, 120), 30); begin     if auth.uid() is null then         raise exception 'Not authenticated';     end if;      delete from public.record_locks     where table_name = p_table_name       and record_id = p_record_id       and lock_expires_at < now();      insert into public.record_locks (         table_name,         record_id,         editor_user_id,         editor_name,         lock_session_id,         locked_at,         lock_expires_at     ) values (         p_table_name,         p_record_id,         auth.uid(),         nullif(trim(p_editor_name), ''),         coalesce(nullif(trim(p_editor_name), ''), auth.uid()::text) || ':' || gen_random_uuid()::text,         now(),         now() + make_interval(secs => v_ttl)     )     on conflict (table_name, record_id)     do update     set         editor_user_id = excluded.editor_user_id,         editor_name = excluded.editor_name,         lock_session_id = excluded.lock_session_id,         locked_at = now(),         lock_expires_at = now() + make_interval(secs => v_ttl)     where public.record_locks.editor_user_id = auth.uid()        or public.record_locks.lock_expires_at < now()     returning * into v_lock;      if v_lock.lock_id is not null then         return jsonb_build_object(             'acquired', true,             'lock', jsonb_build_object(                 'table_name', v_lock.table_name,                 'record_id', v_lock.record_id,                 'editor_user_id', v_lock.editor_user_id,                 'editor_name', v_lock.editor_name,                 'lock_session_id', v_lock.lock_session_id,                 'locked_at', v_lock.locked_at,                 'heartbeat_at', v_lock.lock_expires_at             )         );     end if;      select * into v_existing     from public.record_locks     where table_name = p_table_name       and record_id = p_record_id;      return jsonb_build_object(         'acquired', false,         'lock', case             when v_existing.lock_id is null then null             else jsonb_build_object(                 'table_name', v_existing.table_name,                 'record_id', v_existing.record_id,                 'editor_user_id', v_existing.editor_user_id,                 'editor_name', v_existing.editor_name,                 'lock_session_id', v_existing.lock_session_id,                 'locked_at', v_existing.locked_at,                 'heartbeat_at', v_existing.lock_expires_at             )         end     ); end; $function$; CREATE OR REPLACE FUNCTION public.get_purchase_orders_with_details(in_page integer, in_rows_per_page integer, in_filter_field text, in_filter_data text, in_sort_field text, in_sort_order integer)  RETURNS jsonb  LANGUAGE plpgsql  STABLE AS $function$declare   v_po_ids bigint[];   v_total_count bigint;   v_result jsonb; begin   select total_count, po_ids   into v_total_count, v_po_ids   from public._get_purchase_order_ids_helper(     in_page,     in_rows_per_page,     in_filter_field,     in_filter_data,     in_sort_field,     in_sort_order   );    if v_po_ids is null or array_length(v_po_ids, 1) = 0 then     v_result := jsonb_build_object(       'total_count', coalesce(v_total_count, 0),       'page', in_page,       'rows_per_page', in_rows_per_page,       'purchase_orders', jsonb '[]',       'all_boxes', jsonb '[]',       'all_po_recipes', jsonb '[]',       'all_recipes', jsonb '[]',       'all_recipe_elements', jsonb '[]',       'all_products', jsonb '[]',       'all_po_raw_lines', jsonb '[]',       'all_invoices', jsonb '[]',       'all_boxes_ids', jsonb '[]',       'all_po_recipes_ids', jsonb '[]',       'all_products_ids', jsonb '[]',       'all_po_raw_lines_ids', jsonb '[]',       'all_invoices_ids', jsonb '[]',       'purchase_order_ids', jsonb '[]'     );     return v_result;   end if;    with selected_pos as (     select po.*     from purchase_orders po     where po.purchase_order_id = any(v_po_ids)     order by array_position(v_po_ids, po.purchase_order_id)   ),    po_cases as (     select       c.*,       p.product_id as product_product_id,       p.name as product_name,       p.fnsku as product_fnsku,       p.asin as product_asin,       p.item_num as product_item_num,       p.upc as product_upc     from cases c     left join products p on c.product_id = p.product_id     where c.purchase_order_id = any(v_po_ids)   ),    individual_boxes_agg as (     select       c.purchase_order_id,       jsonb_agg(         jsonb_build_object(           'case_id', c.case_id,           'units_per_case', c.units_per_case,           'date_received', c.date_received,           'notes', c.notes,           'product_id', c.product_id,           'product_name', c.product_name,           'location_id', c.location_id,           'status', c.status,           'purchase_order_id', c.purchase_order_id,           'request_id', c.request_id,           'item_num', c.product_item_num,           'upc', c.product_upc         ) order by c.case_id       ) as individual_boxes_json     from po_cases c     where coalesce(nullif(c.product_fnsku, ''), nullif(c.product_asin, '')) is null     group by c.purchase_order_id   ),    grouped_boxes as (     select       pb.purchase_order_id,       jsonb_agg(         jsonb_build_object(           'product_id', pb.product_product_id,           'product_name', pb.product_name,           'fnsku', pb.product_fnsku,           'asin', pb.product_asin,           'item_num', pb.product_item_num,           'upc', pb.product_upc,           'amount', pb.cnt,           'total_units', pb.total_units         ) order by pb.product_product_id       ) as grouped_boxes_json     from (       select         purchase_order_id,         product_product_id,         product_name,         product_fnsku,         product_asin,         product_item_num,         product_upc,         count(*) as cnt,         coalesce(sum(units_per_case), 0) as total_units       from po_cases       where coalesce(nullif(product_fnsku, ''), nullif(product_asin, '')) is null       group by purchase_order_id, product_product_id, product_name, product_fnsku, product_asin, product_item_num, product_upc     ) pb     group by pb.purchase_order_id   ),    grouped_cases as (     select       pc.purchase_order_id,       jsonb_agg(         jsonb_build_object(           'product_id', pc.product_product_id,           'product_name', pc.product_name,           'fnsku', pc.product_fnsku,           'asin', pc.product_asin,           'item_num', pc.product_item_num,           'upc', pc.product_upc,           'amount', pc.cnt,           'total_units', pc.total_units         ) order by pc.product_product_id       ) as grouped_cases_json     from (       select         purchase_order_id,         product_product_id,         product_name,         product_fnsku,         product_asin,         product_item_num,         product_upc,         count(*) as cnt,         coalesce(sum(units_per_case), 0) as total_units       from po_cases       where coalesce(nullif(product_fnsku, ''), nullif(product_asin, '')) is not null       group by purchase_order_id, product_product_id, product_name, product_fnsku, product_asin, product_item_num, product_upc     ) pc     group by pc.purchase_order_id   ),    po_recipes_per_po as (     select       pr.purchase_order_id,       jsonb_agg(to_jsonb(pr) order by pr.po_recipe_id) as po_recipes_json,       array_agg(pr.recipe_id) filter (where pr.recipe_id is not null) as recipe_ids     from po_recipes pr     where pr.purchase_order_id = any(v_po_ids)     group by pr.purchase_order_id   ),    recipes_for_page as (     select r.*     from recipes r     where r.recipe_id in (       select distinct recipe_id       from po_recipes       where purchase_order_id = any(v_po_ids)     )   ),    recipe_elements_for_page as (     select re.*     from recipe_elements re     where re.recipe_id in (select recipe_id from recipes_for_page)   ),    per_po_recipes_json as (     select       p.purchase_order_id,       coalesce(p.po_recipes_json, '[]'::jsonb) as po_recipes_json,       coalesce(         (           select jsonb_agg(to_jsonb(r) order by r.recipe_id)           from recipes_for_page r           where r.recipe_id = any(p.recipe_ids)         ),         '[]'::jsonb       ) as recipes_json,       coalesce(         (           select jsonb_agg(to_jsonb(re) order by re.recipe_element_id)           from recipe_elements_for_page re           where re.recipe_id = any(p.recipe_ids)         ),         '[]'::jsonb       ) as recipe_elements_json     from po_recipes_per_po p   ),    -- Enrich po_raw_lines with key product fields for UI display.   po_raw_lines_with_products as (     select       prl.*,       p.name as product_name,       p.upc as product_upc,       p.item_num as product_item_num,       p.price_2023 as product_price,       p.default_units_per_case as product_default_units_per_case     from po_raw_lines prl     left join products p on p.product_id = prl.product_id     where prl.purchase_order_id = any(v_po_ids)   ),    po_raw_lines_per_po as (     select       prl.purchase_order_id,       coalesce(         jsonb_agg(           jsonb_build_object(             'po_raw_line_id', prl.po_raw_line_id,             'purchase_order_id', prl.purchase_order_id,             'product_id', prl.product_id,             'invoice_id', prl.invoice_id,             'total_units', prl.total_units,             'status', prl.status,             'notes', prl.notes,             'product_name', prl.product_name,             'upc', prl.product_upc,             'item_num', prl.product_item_num,             'unit_price', prl.product_price,             'default_units_per_case', prl.product_default_units_per_case           ) order by prl.po_raw_line_id         ),         '[]'::jsonb       ) as po_raw_lines_json     from po_raw_lines_with_products prl     group by prl.purchase_order_id   ),    invoices_per_po as (     select       i.purchase_order_id,       coalesce(jsonb_agg(to_jsonb(i) order by i.invoice_id), '[]'::jsonb) as invoices_json     from invoices i     where i.purchase_order_id = any(v_po_ids)     group by i.purchase_order_id   ),    all_boxes_agg as (     select coalesce(jsonb_agg(       jsonb_build_object(         'case_id', c.case_id,         'purchase_order_id', c.purchase_order_id,         'product_id', c.product_id,         'product_name', c.product_name,         'units_per_case', c.units_per_case,         'status', c.status,         'location_id', c.location_id,         'request_id', c.request_id,         'date_received', c.date_received,         'notes', c.notes,         'item_num', c.product_item_num,         'upc', c.product_upc       ) order by c.case_id     ), '[]'::jsonb) as j     from po_cases c     where coalesce(nullif(c.product_fnsku, ''), nullif(c.product_asin, '')) is null   ),    all_boxes_ids_agg as (     select coalesce(jsonb_agg(c.case_id order by c.case_id), '[]'::jsonb) as j     from po_cases c     where coalesce(nullif(c.product_fnsku, ''), nullif(c.product_asin, '')) is null   ),    all_po_recipes_agg as (     select coalesce(jsonb_agg(       jsonb_build_object(         'po_recipe_id', pr.po_recipe_id,         'purchase_order_id', pr.purchase_order_id,         'recipe_id', pr.recipe_id,         'qty', pr.qty       ) order by pr.po_recipe_id     ), '[]'::jsonb) as j     from po_recipes pr     where pr.purchase_order_id = any(v_po_ids)   ),    all_po_recipes_ids_agg as (     select coalesce(jsonb_agg(pr.po_recipe_id order by pr.po_recipe_id), '[]'::jsonb) as j     from po_recipes pr     where pr.purchase_order_id = any(v_po_ids)   ),    all_recipes_agg as (     select coalesce(jsonb_agg(to_jsonb(r) order by r.recipe_id), '[]'::jsonb) as j     from recipes_for_page r   ),    all_recipe_elements_agg as (     select coalesce(jsonb_agg(to_jsonb(re) order by re.recipe_element_id), '[]'::jsonb) as j     from recipe_elements_for_page re   ),    all_products_agg as (     select coalesce(jsonb_agg(to_jsonb(p) order by p.product_id), '[]'::jsonb) as j     from products p     where p.product_id in (select distinct product_id from po_cases)        or p.product_id in (select distinct product_id from recipe_elements_for_page)        or p.product_id in (select distinct product_id from po_raw_lines_with_products)   ),    all_products_ids_agg as (     select coalesce(jsonb_agg(distinct product_id order by product_id), '[]'::jsonb) as j     from (       select product_id from po_cases       union       select product_id from recipe_elements_for_page       union       select product_id from po_raw_lines_with_products     ) product_ids   ),    all_po_raw_lines_agg as (     select       coalesce(         jsonb_agg(           jsonb_build_object(             'po_raw_line_id', prl.po_raw_line_id,             'purchase_order_id', prl.purchase_order_id,             'product_id', prl.product_id,             'invoice_id', prl.invoice_id,             'total_units', prl.total_units,             'status', prl.status,             'notes', prl.notes,             'product_name', prl.product_name,             'upc', prl.product_upc,             'item_num', prl.product_item_num,             'unit_price', prl.product_price,             'default_units_per_case', prl.product_default_units_per_case           ) order by prl.po_raw_line_id         ),         '[]'::jsonb       ) as j     from po_raw_lines_with_products prl   ),        all_po_raw_lines_ids_agg as (         select coalesce(jsonb_agg(prl.po_raw_line_id order by prl.po_raw_line_id), '[]'::jsonb) as j         from po_raw_lines_with_products prl       ),    all_invoices_agg as (     select coalesce(jsonb_agg(to_jsonb(i) order by i.invoice_id), '[]'::jsonb) as j     from invoices i     where i.purchase_order_id = any(v_po_ids)       ),        all_invoices_ids_agg as (         select coalesce(jsonb_agg(i.invoice_id order by i.invoice_id), '[]'::jsonb) as j         from invoices i         where i.purchase_order_id = any(v_po_ids)   )    select jsonb_build_object(     'total_count', v_total_count,     'page', in_page,     'rows_per_page', in_rows_per_page,     'purchase_orders',       coalesce(         jsonb_agg(           jsonb_build_object(             'purchase_order_id', sp.purchase_order_id,             'purchase_order_name', sp.purchase_order_name,             'vendor_id', sp.vendor_id,             'date_ordered', sp.date_ordered,             'date_received', sp.date_received,             'notes', sp.notes,             'status', sp.status,             'discount', sp.discount,             'vendor_name', v.vendor_name,             'grouped_cases', coalesce(gc.grouped_cases_json, '[]'::jsonb),             'grouped_boxes', coalesce(gb.grouped_boxes_json, '[]'::jsonb),             'individual_boxes', coalesce(ib.individual_boxes_json, '[]'::jsonb),             'po_recipes', coalesce(pr.po_recipes_json, '[]'::jsonb),             'recipes', coalesce(pr.recipes_json, '[]'::jsonb),             'recipe_elements', coalesce(pr.recipe_elements_json, '[]'::jsonb),             'po_raw_lines', coalesce(prl.po_raw_lines_json, '[]'::jsonb),             'invoices', coalesce(pi.invoices_json, '[]'::jsonb)           ) order by array_position(v_po_ids, sp.purchase_order_id)         ),         '[]'::jsonb       ),     'all_boxes', (select j from all_boxes_agg),     'all_po_recipes', (select j from all_po_recipes_agg),     'all_recipes', (select j from all_recipes_agg),     'all_recipe_elements', (select j from all_recipe_elements_agg),     'all_products', (select j from all_products_agg),     'all_po_raw_lines', (select j from all_po_raw_lines_agg),     'all_invoices', (select j from all_invoices_agg),     'all_boxes_ids', (select j from all_boxes_ids_agg),     'all_po_recipes_ids', (select j from all_po_recipes_ids_agg),     'all_products_ids', (select j from all_products_ids_agg),     'all_po_raw_lines_ids', (select j from all_po_raw_lines_ids_agg),     'all_invoices_ids', (select j from all_invoices_ids_agg),     'purchase_order_ids', to_jsonb(v_po_ids)   )   into v_result   from selected_pos sp   left join vendors v on v.vendor_id = sp.vendor_id   left join grouped_cases gc on gc.purchase_order_id = sp.purchase_order_id   left join grouped_boxes gb on gb.purchase_order_id = sp.purchase_order_id   left join individual_boxes_agg ib on ib.purchase_order_id = sp.purchase_order_id   left join per_po_recipes_json pr on pr.purchase_order_id = sp.purchase_order_id   left join po_raw_lines_per_po prl on prl.purchase_order_id = sp.purchase_order_id   left join invoices_per_po pi on pi.purchase_order_id = sp.purchase_order_id;    return v_result; end;$function$; CREATE FUNCTION public.get_record_lock(p_table_name text, p_record_id text)  RETURNS jsonb  LANGUAGE plpgsql AS $function$ declare     v_lock public.record_locks; begin     select * into v_lock     from public.record_locks     where table_name = p_table_name             and record_id = p_record_id             and lock_expires_at >= now();      if v_lock.lock_id is null then         return null;     end if;      return jsonb_build_object(         'table_name', v_lock.table_name,         'record_id', v_lock.record_id,         'editor_user_id', v_lock.editor_user_id,         'editor_name', v_lock.editor_name,         'lock_session_id', v_lock.lock_session_id,         'locked_at', v_lock.locked_at,         'heartbeat_at', v_lock.lock_expires_at     ); end; $function$; CREATE FUNCTION public.get_requests_to_process_with_details(in_page integer, in_rows_per_page integer, in_filter_field text, in_filter_data text, in_sort_field text, in_sort_order integer, in_status_exclude text)  RETURNS jsonb  LANGUAGE plpgsql  STABLE AS $function$ DECLARE   v_request_ids bigint[];   v_total_count bigint;   v_result jsonb; BEGIN   SELECT total_count, request_ids   INTO v_total_count, v_request_ids   FROM public._get_requests_to_process_ids_helper(     in_page,     in_rows_per_page,     in_filter_field,     in_filter_data,     in_sort_field,     in_sort_order,     in_status_exclude   );    IF v_request_ids IS NULL OR array_length(v_request_ids, 1) = 0 THEN     RETURN jsonb_build_object(       'total_count', COALESCE(v_total_count, 0),       'page', in_page,       'rows_per_page', in_rows_per_page,       'requests_to_process', jsonb '[]',       'all_purchase_orders', jsonb '[]',       'all_po_recipes', jsonb '[]',       'all_recipes', jsonb '[]',       'all_recipe_elements', jsonb '[]',       'all_products', jsonb '[]'     );   END IF;    WITH selected_requests AS (     SELECT r.*     FROM public.requests_to_process r     WHERE r.request_id = ANY(v_request_ids)     ORDER BY array_position(v_request_ids, r.request_id)   ),   linked_purchase_orders AS (     SELECT po.*     FROM public.purchase_orders po     WHERE po.purchase_order_id IN (       SELECT DISTINCT purchase_order_id       FROM selected_requests       WHERE purchase_order_id IS NOT NULL     )   ),   linked_po_recipes AS (     SELECT pr.*     FROM public.po_recipes pr     WHERE pr.purchase_order_id IN (       SELECT purchase_order_id FROM linked_purchase_orders     )   ),   linked_recipes AS (     SELECT r.*     FROM public.recipes r     WHERE r.recipe_id IN (       SELECT DISTINCT recipe_id       FROM linked_po_recipes       WHERE recipe_id IS NOT NULL     )   ),   linked_recipe_elements AS (     SELECT re.*     FROM public.recipe_elements re     WHERE re.recipe_id IN (       SELECT recipe_id FROM linked_recipes     )   ),   linked_products AS (     SELECT p.*     FROM public.products p     WHERE p.product_id IN (       SELECT DISTINCT product_id FROM selected_requests       UNION       SELECT DISTINCT product_id FROM linked_recipe_elements     )   )   SELECT jsonb_build_object(     'total_count', COALESCE(v_total_count, 0),     'page', in_page,     'rows_per_page', in_rows_per_page,     'requests_to_process', COALESCE((SELECT jsonb_agg(to_jsonb(sr) ORDER BY array_position(v_request_ids, sr.request_id)) FROM selected_requests sr), '[]'::jsonb),     'all_purchase_orders', COALESCE((SELECT jsonb_agg(to_jsonb(po) ORDER BY po.purchase_order_id) FROM linked_purchase_orders po), '[]'::jsonb),     'all_po_recipes', COALESCE((SELECT jsonb_agg(to_jsonb(pr) ORDER BY pr.po_recipe_id) FROM linked_po_recipes pr), '[]'::jsonb),     'all_recipes', COALESCE((SELECT jsonb_agg(to_jsonb(r) ORDER BY r.recipe_id) FROM linked_recipes r), '[]'::jsonb),     'all_recipe_elements', COALESCE((SELECT jsonb_agg(to_jsonb(re) ORDER BY re.recipe_element_id) FROM linked_recipe_elements re), '[]'::jsonb),     'all_products', COALESCE((SELECT jsonb_agg(to_jsonb(p) ORDER BY p.product_id) FROM linked_products p), '[]'::jsonb)   ) INTO v_result;    RETURN v_result; END; $function$; CREATE OR REPLACE FUNCTION public.handle_new_user()  RETURNS trigger  LANGUAGE plpgsql  SECURITY DEFINER  SET search_path TO '' AS $function$ begin   insert into public.profiles (id, full_name, avatar_url)   values (new.id, new.raw_user_meta_data->>'full_name', new.raw_user_meta_data->>'avatar_url');   return new; end; $function$; CREATE OR REPLACE FUNCTION public.import_processed_product_keys(product_name text, date_added timestamp with time zone, do_we_carry text, vendor_name text, fnsku text, asin text, default_units_per_case integer, weight_lbs integer, box_type text, box_cost numeric, process_time_per_unit_sec integer, meltable text, products_needed_a text, item_num_a text, qty_1 integer, products_needed_b text, item_num_b text, qty_2 integer, products_needed_c text, item_num_c text, qty_3 integer, products_needed_d text, item_num_d text, qty_4 integer, products_needed_e text, item_num_e text, qty_5 integer, products_needed_f text, item_num_f text, qty_6 integer, bag_cost numeric, in_shipping_cost numeric, out_shipping_cost numeric, labor_cost numeric, item_cost numeric, unit_box_cost numeric, misc_cost numeric, amz_fees_cost numeric, storage_cost_30_day numeric, holiday_storage_cost numeric, total_cost numeric, total_holiday_cost numeric, notes text)  RETURNS void  LANGUAGE plpgsql AS $function$ DECLARE     current_vendor_name text;     current_vendor_id bigint;     added_product_id bigint;     recipe_label text;     added_recipe_id bigint;     product_a_id bigint;     product_b_id bigint;     product_c_id bigint;     product_d_id bigint;     product_e_id bigint;     product_f_id bigint; BEGIN     -- Split the line into fields (assuming comma-separated values)     current_vendor_name = vendor_name; -- Adjust index based on your CSV structure      RAISE LOG 'vendor name: %', vendor_name;      -- Check if vendor exists     SELECT v.vendor_id INTO current_vendor_id FROM vendors v WHERE LOWER(v.vendor_name) = LOWER(current_vendor_name);      -- If vendor does not exist, insert it     IF current_vendor_id IS NULL THEN         INSERT INTO vendors (vendor_name) VALUES (current_vendor_name) RETURNING vendor_id INTO current_vendor_id;     END IF;      -- Validate required fields before inserting     IF product_name IS NULL THEN         RAISE EXCEPTION 'Required fields are missing: product_name: %', product_name;         RETURN; -- Skip this iteration if required fields are missing     END IF;      IF current_vendor_id IS NULL THEN         RAISE EXCEPTION 'Required fields are missing for product %: current_vendor_id: %', product_name, current_vendor_id;         RETURN; -- Skip this iteration if required fields are missing     END IF;      IF products_needed_a IS NULL THEN          RAISE EXCEPTION 'Product % requires at least one input recipe ingredient: products_needed_a: %', product_name, products_needed_a;         RETURN;     END IF;      IF products_needed_a IS NOT NULL AND qty_1 IS NOT NULL THEN          SELECT product_id INTO product_a_id FROM product WHERE LOWER(name) = LOWER(products_needed_a);     END IF;      IF product_a_id IS NULL THEN          RAISE EXCEPTION 'Product % requires at least one input recipe ingredient: products_needed_a: %', product_name, products_needed_a;         RETURN;     END IF;      IF products_needed_b IS NOT NULL AND qty_2 IS NOT NULL THEN          SELECT product_id INTO product_b_id FROM product WHERE LOWER(name) = LOWER(products_needed_b);     END IF;      IF products_needed_c IS NOT NULL AND qty_3 IS NOT NULL THEN          SELECT product_id INTO product_c_id FROM product WHERE LOWER(name) = LOWER(products_needed_c);     END IF;      IF products_needed_d IS NOT NULL AND qty_4 IS NOT NULL THEN          SELECT product_id INTO product_d_id FROM product WHERE LOWER(name) = LOWER(products_needed_d);     END IF;      IF products_needed_e IS NOT NULL AND qty_5 IS NOT NULL THEN          SELECT product_id INTO product_e_id FROM product WHERE LOWER(name) = LOWER(products_needed_e);     END IF;      IF products_needed_f IS NOT NULL AND qty_6 IS NOT NULL THEN          SELECT product_id INTO product_f_id FROM product WHERE LOWER(name) = LOWER(products_needed_f);     END IF;      -- Insert the product record (adjust the fields as necessary)     INSERT INTO products (name, date_added, do_we_carry, vendor_id, fnsku, asin, default_units_per_case, weight_lbs, box_type, box_cost, process_time_per_unit_sec,      meltable, bag_cost, in_shipping_cost, out_shipping_cost, labor_cost, item_cost, unit_box_cost, misc_cost, amz_fees_cost, storage_cost_30_day, holiday_storage_cost, total_cost,     total_holiday_cost, notes) VALUES (         product_name, -- Product name         date_added, -- Item number         do_we_carry, -- Product UPC         current_vendor_id,         fnsku,          asin,          default_units_per_case,          weight_lbs, box_type,          box_cost,          process_time_per_unit_sec,          meltable,          bag_cost,          in_shipping_cost,          out_shipping_cost,          labor_cost, item_cost,          unit_box_cost, misc_cost,          amz_fees_cost,          storage_cost_30_day,          holiday_storage_cost,          total_cost,         total_holiday_cost,          notes -- Product key notes     ) RETURNING product_id INTO added_product_id;      -- Create recipe based on the products required fields     recipe_label = format('%s - %s', product_name, fnsku);      INSERT INTO recipes (label, vendor_id) VALUES (recipe_label, current_vendor_id) RETURNING recipe_id INTO added_recipe_id;      -- Create a recipe element for the processed product output and however many input elements there are     INSERT INTO recipe_elements (recipe_id, product_id, type, qty) VALUES (added_recipe_id, added_product_id, 'output', 1);      IF product_a_id IS NOT NULL THEN         INSERT INTO recipe_elements (recipe_id, product_id, type, qty) VALUES (added_recipe_id, product_a_id, 'input', qty_1);     END IF;      IF product_b_id IS NOT NULL THEN         INSERT INTO recipe_elements (recipe_id, product_id, type, qty) VALUES (added_recipe_id, product_b_id, 'input', qty_2);     END IF;      IF product_c_id IS NOT NULL THEN         INSERT INTO recipe_elements (recipe_id, product_id, type, qty) VALUES (added_recipe_id, product_c_id, 'input', qty_3);     END IF;      IF product_d_id IS NOT NULL THEN         INSERT INTO recipe_elements (recipe_id, product_id, type, qty) VALUES (added_recipe_id, product_d_id, 'input', qty_4);     END IF;      IF product_e_id IS NOT NULL THEN         INSERT INTO recipe_elements (recipe_id, product_id, type, qty) VALUES (added_recipe_id, product_e_id, 'input', qty_5);     END IF;      IF product_f_id IS NOT NULL THEN         INSERT INTO recipe_elements (recipe_id, product_id, type, qty) VALUES (added_recipe_id, product_f_id, 'input', qty_6);     END IF;  END; $function$; CREATE FUNCTION public.refresh_record_lock(p_table_name text, p_record_id text, p_ttl_seconds integer DEFAULT 120)  RETURNS jsonb  LANGUAGE plpgsql AS $function$ declare     v_lock public.record_locks;     v_ttl integer := greatest(coalesce(p_ttl_seconds, 120), 30); begin     if auth.uid() is null then         raise exception 'Not authenticated';     end if;      update public.record_locks     set         lock_expires_at = now() + make_interval(secs => v_ttl),         editor_name = coalesce(editor_name, auth.uid()::text)     where table_name = p_table_name       and record_id = p_record_id       and editor_user_id = auth.uid()     returning * into v_lock;      if v_lock.lock_id is null then         return jsonb_build_object('refreshed', false);     end if;      return jsonb_build_object(         'refreshed', true,         'lock', jsonb_build_object(             'table_name', v_lock.table_name,             'record_id', v_lock.record_id,             'editor_user_id', v_lock.editor_user_id,             'editor_name', v_lock.editor_name,             'lock_session_id', v_lock.lock_session_id,             'locked_at', v_lock.locked_at,             'heartbeat_at', v_lock.lock_expires_at         )     ); end; $function$; CREATE FUNCTION public.release_record_lock(p_table_name text, p_record_id text)  RETURNS jsonb  LANGUAGE plpgsql AS $function$ declare     v_deleted public.record_locks; begin     if auth.uid() is null then         raise exception 'Not authenticated';     end if;      delete from public.record_locks     where table_name = p_table_name       and record_id = p_record_id       and editor_user_id = auth.uid()     returning * into v_deleted;      return jsonb_build_object('released', v_deleted.lock_id is not null); end; $function$; ALTER TABLE public.cases ENABLE ROW LEVEL SECURITY; CREATE POLICY can_read_cases ON public.cases FOR SELECT TO authenticated USING (true); ALTER TABLE public.invoices ENABLE ROW LEVEL SECURITY; CREATE POLICY can_read_invoices ON public.invoices FOR SELECT TO authenticated USING (true); ALTER TABLE public.locations ENABLE ROW LEVEL SECURITY; CREATE POLICY can_create_locations ON public.locations FOR INSERT TO authenticated WITH CHECK (true); CREATE POLICY can_read_locations ON public.locations FOR SELECT TO authenticated USING (true); ALTER TABLE public.picklist_elements ENABLE ROW LEVEL SECURITY; ALTER TABLE public.picklists ENABLE ROW LEVEL SECURITY; ALTER TABLE public.picklists ADD COLUMN assigned_user_id uuid; ALTER TABLE public.picklists ADD CONSTRAINT picklists_assigned_user_id_fkey FOREIGN KEY (assigned_user_id) REFERENCES public.profiles(id); CREATE TABLE public.po_raw_lines (po_raw_line_id bigint GENERATED ALWAYS AS IDENTITY NOT NULL, product_id bigint NOT NULL, purchase_order_id bigint NOT NULL, invoice_id bigint, total_units numeric NOT NULL, notes text, status text); CREATE FUNCTION public.bulk_create_po_raw_lines(record_array jsonb)  RETURNS SETOF public.po_raw_lines  LANGUAGE plpgsql AS $function$ begin   if record_array is null or jsonb_typeof(record_array) <> 'array' then     raise exception 'record_array must be a JSON array';   end if;    return query   with parsed_rows as (     select       (row_value->>'product_id')::bigint as product_id,       (row_value->>'purchase_order_id')::bigint as purchase_order_id,       nullif(row_value->>'invoice_id', '')::bigint as invoice_id,       (row_value->>'total_units')::numeric as total_units,       nullif(row_value->>'notes', '')::text as notes,       (row_value->>'status')::text as status     from jsonb_array_elements(record_array) as row_value   )   insert into public.po_raw_lines (     product_id,     purchase_order_id,     invoice_id,     total_units,     notes,     status   )   select     parsed_rows.product_id,     parsed_rows.purchase_order_id,     parsed_rows.invoice_id,     parsed_rows.total_units,     parsed_rows.notes,     parsed_rows.status   from parsed_rows   returning *; end; $function$; ALTER TABLE public.po_raw_lines ENABLE ROW LEVEL SECURITY; ALTER TABLE public.po_raw_lines ADD CONSTRAINT po_raw_lines_invoice_id_fkey FOREIGN KEY (invoice_id) REFERENCES public.invoices(invoice_id); ALTER TABLE public.po_raw_lines ADD CONSTRAINT po_raw_lines_pkey PRIMARY KEY (po_raw_line_id); ALTER TABLE public.po_raw_lines ADD CONSTRAINT po_raw_lines_product_id_fkey FOREIGN KEY (product_id) REFERENCES public.products(product_id) ON DELETE CASCADE; ALTER TABLE public.po_raw_lines ADD CONSTRAINT po_raw_lines_purchase_order_id_fkey FOREIGN KEY (purchase_order_id) REFERENCES public.purchase_orders(purchase_order_id) ON DELETE CASCADE; CREATE POLICY can_read_po_raw_lines ON public.po_raw_lines FOR SELECT TO authenticated USING (true); ALTER TABLE public.po_recipes ENABLE ROW LEVEL SECURITY; CREATE POLICY can_read_po_recipes ON public.po_recipes FOR SELECT TO authenticated USING (true); ALTER TABLE public.products ENABLE ROW LEVEL SECURITY; CREATE POLICY can_read_products ON public.products FOR SELECT TO authenticated USING (true); ALTER TABLE public.profiles ADD COLUMN company_role text DEFAULT 'Packing Associate'::text; CREATE POLICY can_create_cases ON public.cases FOR INSERT TO authenticated WITH CHECK ((EXISTS ( SELECT 1    FROM public.profiles p   WHERE ((p.id = auth.uid()) AND (p.company_role = ANY (ARRAY['Admin'::text, 'Management'::text])))))); CREATE POLICY can_delete_cases ON public.cases FOR DELETE TO authenticated USING ((EXISTS ( SELECT 1    FROM public.profiles p   WHERE ((p.id = auth.uid()) AND (p.company_role = ANY (ARRAY['Admin'::text, 'Management'::text])))))); CREATE POLICY can_update_cases ON public.cases FOR UPDATE TO authenticated USING ((EXISTS ( SELECT 1    FROM public.profiles p   WHERE ((p.id = auth.uid()) AND (p.company_role = ANY (ARRAY['Admin'::text, 'Management'::text])))))) WITH CHECK ((EXISTS ( SELECT 1    FROM public.profiles p   WHERE ((p.id = auth.uid()) AND (p.company_role = ANY (ARRAY['Admin'::text, 'Management'::text])))))); CREATE POLICY can_create_invoices ON public.invoices FOR INSERT TO authenticated WITH CHECK ((EXISTS ( SELECT 1    FROM public.profiles p   WHERE ((p.id = auth.uid()) AND (p.company_role = ANY (ARRAY['Admin'::text, 'Management'::text])))))); CREATE POLICY can_delete_invoices ON public.invoices FOR DELETE TO authenticated USING ((EXISTS ( SELECT 1    FROM public.profiles p   WHERE ((p.id = auth.uid()) AND (p.company_role = ANY (ARRAY['Admin'::text, 'Management'::text])))))); CREATE POLICY can_update_invoices ON public.invoices FOR UPDATE TO authenticated USING ((EXISTS ( SELECT 1    FROM public.profiles p   WHERE ((p.id = auth.uid()) AND (p.company_role = ANY (ARRAY['Admin'::text, 'Management'::text])))))) WITH CHECK ((EXISTS ( SELECT 1    FROM public.profiles p   WHERE ((p.id = auth.uid()) AND (p.company_role = ANY (ARRAY['Admin'::text, 'Management'::text])))))); CREATE POLICY can_delete_locations ON public.locations FOR DELETE TO authenticated USING ((EXISTS ( SELECT 1    FROM public.profiles p   WHERE ((p.id = auth.uid()) AND (p.company_role = ANY (ARRAY['Admin'::text, 'Management'::text])))))); CREATE POLICY can_update_locations ON public.locations FOR UPDATE TO authenticated USING ((EXISTS ( SELECT 1    FROM public.profiles p   WHERE ((p.id = auth.uid()) AND (p.company_role = ANY (ARRAY['Admin'::text, 'Management'::text])))))) WITH CHECK ((EXISTS ( SELECT 1    FROM public.profiles p   WHERE ((p.id = auth.uid()) AND (p.company_role = ANY (ARRAY['Admin'::text, 'Management'::text])))))); CREATE POLICY can_create_picklist_elements ON public.picklist_elements FOR INSERT TO authenticated WITH CHECK ((EXISTS ( SELECT 1    FROM public.profiles p   WHERE ((p.id = auth.uid()) AND (p.company_role = ANY (ARRAY['Admin'::text, 'Management'::text])))))); CREATE POLICY can_delete_picklist_elements ON public.picklist_elements FOR DELETE TO authenticated USING ((EXISTS ( SELECT 1    FROM public.profiles p   WHERE ((p.id = auth.uid()) AND (p.company_role = ANY (ARRAY['Admin'::text, 'Management'::text])))))); CREATE POLICY can_read_picklist_elements ON public.picklist_elements FOR SELECT TO authenticated USING (((( SELECT profiles.company_role    FROM public.profiles   WHERE (profiles.id = auth.uid())) = ANY (ARRAY['Admin'::text, 'Management'::text])) OR (EXISTS ( SELECT 1    FROM public.picklists p   WHERE ((p.picklist_id = picklist_elements.picklist_id) AND (p.assigned_user_id = auth.uid())))))); CREATE POLICY can_update_picklist_elements ON public.picklist_elements FOR UPDATE TO authenticated USING (((EXISTS ( SELECT 1    FROM public.profiles p   WHERE ((p.id = auth.uid()) AND (p.company_role = ANY (ARRAY['Admin'::text, 'Management'::text]))))) OR (EXISTS ( SELECT 1    FROM public.picklists p   WHERE ((p.picklist_id = picklist_elements.picklist_id) AND (p.assigned_user_id = auth.uid())))))) WITH CHECK (((EXISTS ( SELECT 1    FROM public.profiles p   WHERE ((p.id = auth.uid()) AND (p.company_role = ANY (ARRAY['Admin'::text, 'Management'::text]))))) OR (EXISTS ( SELECT 1    FROM public.picklists p   WHERE ((p.picklist_id = picklist_elements.picklist_id) AND (p.assigned_user_id = auth.uid())))))); CREATE POLICY can_create_picklists ON public.picklists FOR INSERT TO authenticated WITH CHECK ((EXISTS ( SELECT 1    FROM public.profiles p   WHERE ((p.id = auth.uid()) AND (p.company_role = ANY (ARRAY['Admin'::text, 'Management'::text])))))); CREATE POLICY can_delete_picklists ON public.picklists FOR DELETE TO authenticated USING ((EXISTS ( SELECT 1    FROM public.profiles p   WHERE ((p.id = auth.uid()) AND (p.company_role = ANY (ARRAY['Admin'::text, 'Management'::text])))))); CREATE POLICY can_read_picklists ON public.picklists FOR SELECT TO authenticated USING (((( SELECT profiles.company_role    FROM public.profiles   WHERE (profiles.id = auth.uid())) = ANY (ARRAY['Admin'::text, 'Management'::text])) OR (assigned_user_id = auth.uid()))); CREATE POLICY can_update_picklists ON public.picklists FOR UPDATE TO authenticated USING (((EXISTS 